[
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 103,
    "severity": "critical",
    "description": "setUserState mutation always passes assignedBy even when state is 'inherit', violating the service's discriminated union type contract. The FeatureOptInService.setUserFeatureState signature expects: {userId, featureId, state: 'inherit'} OR {userId, featureId, state: 'enabled'|'disabled', assignedBy}. When state is 'inherit', assignedBy must not be provided. This is a compliance violation that breaks the established type safety pattern.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -101,11 +101,18 @@
           message: "Invalid slug. This feature is not opt-in configurable.",
         });
       }
-
-      await featureOptInService.setUserFeatureState({
-        userId: ctx.user.id,
-        featureId: input.slug,
-        state: input.state,
-        assignedBy: ctx.user.id,
+    
+    if (input.state === "inherit") {
+      await featureOptInService.setUserFeatureState({
+        userId: ctx.user.id,
+        featureId: input.slug,
+        state: input.state,
       });
+    } else {
+      await featureOptInService.setUserFeatureState({
+        userId: ctx.user.id,
+        featureId: input.slug,
+        state: input.state as "enabled" | "disabled",
+        assignedBy: ctx.user.id,
+      });
+    }
"
  },
